const ROLI_KEY = 'YOUR_ROLI_SUPABASE_ANON_KEY';
const ROLI = 'YOUR_ROLI_SUPABASE_URL/rest/v1';
const QAV_KEY = 'YOUR_QAVONE_SUPABASE_ANON_KEY';
const QAV = 'YOUR_QAVONE_SUPABASE_URL/rest/v1';

// 1. Read sync cursor from ROLI
let lastCursor;
try {
  const rows = await this.helpers.httpRequest({ method: 'GET', url: `${ROLI}/sync_cursors?source=eq.attention&select=last_cursor_iso`, headers: { apikey: ROLI_KEY }, json: true });
  lastCursor = rows?.[0]?.last_cursor_iso || null;
} catch (e) { lastCursor = null; }
if (!lastCursor) {
  const d = new Date(); d.setDate(d.getDate() - 60);
  lastCursor = d.toISOString();
}

// 2. Read ROLI agents for email → id mapping
const agents = await this.helpers.httpRequest({ method: 'GET', url: `${ROLI}/agents?select=id,name,adp_work_email`, headers: { apikey: ROLI_KEY }, json: true });
const emailToId = {};
for (const a of (agents || [])) {
  if (a.adp_work_email) emailToId[a.adp_work_email.toLowerCase()] = a.id;
}

// 3. Paginate QAvOne attention_conversations since cursor
const MIN_DURATION = 120;
const allRows = [];
let offset = 0;
const LIMIT = 500;
let latestImported = lastCursor;

while (true) {
  const url = `${QAV}/attention_conversations?imported_at=gt.${encodeURIComponent(lastCursor)}&duration_sec=gte.${MIN_DURATION}&ai_overall_score=not.is.null&select=attention_uuid,agent_email,agent_name,call_date,duration_sec,ai_overall_score,ai_scorecard_data,title,imported_at,has_been_scored&order=imported_at.asc&limit=${LIMIT}&offset=${offset}`;
  const rows = await this.helpers.httpRequest({ method: 'GET', url, headers: { apikey: QAV_KEY }, json: true });
  if (!Array.isArray(rows) || rows.length === 0) break;
  allRows.push(...rows);
  for (const r of rows) {
    if (r.imported_at && r.imported_at > latestImported) latestImported = r.imported_at;
  }
  if (rows.length < LIMIT) break;
  offset += LIMIT;
}

// 4. Transform to conversation_intelligence schema
const conversations = [];
let matched = 0;
let skipped = 0;
for (const r of allRows) {
  const agentId = r.agent_email ? emailToId[r.agent_email.toLowerCase()] : null;
  if (!agentId) { skipped++; continue; }
  matched++;

  const breakdown = {};
  const scData = r.ai_scorecard_data;
  const items = (scData && scData.items) || [];
  for (const item of items) {
    if (item.score === 0 && item.status === 'CALCULATED' && item.description && item.description.toLowerCase().includes('n/a')) continue;
    const key = (item.title || 'unknown').toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
    if (item.score != null) breakdown[key] = item.score;
  }

  const callDate = r.call_date ? r.call_date.slice(0, 10) : null;

  conversations.push({
    attention_uuid: r.attention_uuid,
    attention_user_uuid: r.agent_email || '',
    call_date: callDate,
    call_started_at: r.call_date,
    duration_seconds: Math.round(r.duration_sec || 0),
    call_label: null,
    outcome: null,
    scorecard_name: (scData && scData.title) || null,
    scorecard_total_score: r.ai_overall_score ? parseFloat(r.ai_overall_score) : null,
    scorecard_breakdown: Object.keys(breakdown).length > 0 ? breakdown : null,
    talk_ratio: null,
    longest_monologue_sec: null,
    sentiment_overall: null,
    first_objection_type: null,
    first_objection_at_seconds: null,
    recovered_after_objection: null,
    clip_url: `https://app.attention.tech/conversations/${r.attention_uuid}`,
    transcript_summary: (scData && scData.summary && scData.summary.summaryText) || null,
    ai_themes: [],
    raw_payload: { source: 'qav1', qav_id: r.attention_uuid, agent_name: r.agent_name, title: r.title },
  });
}

return [{ json: { conversationCount: conversations.length, matched, skipped, latestImported, conversations } }];

